WITH s AS (SELECT s.year, SUM(s.shipped_units) AS shipped_units FROM shipped_raw s GROUP BY s.year), c AS (SELECT c.mapped_year AS year, SUM(c.conceded_units) AS conceded_units FROM concession_raw c GROUP BY c.mapped_year) SELECT s.year, (COALESCE(c.conceded_units, 0) * 100.0) / NULLIF(s.shipped_units, 0) AS return_rate_pct FROM s LEFT JOIN c ON c.year = s.year ORDER BY return_rate_pct DESC NULLS LAST LIMIT 1;